    {modal&&modal.type==='tutorial'&&(()=>{const t=modal.data;return<div style={{position:'fixed',inset:0,background:'rgba(0,0,0,.8)',backdropFilter:'blur(12px)',display:'flex',alignItems:'center',justifyContent:'center',zIndex:1000,padding:20,animation:'fi .2s ease-out'}} onClick={()=>setModal(null)}><div style={{background:'#101014',border:'1px solid rgba(255,255,255,.07)',borderRadius:18,maxWidth:540,width:'100%',maxHeight:'90vh',overflowY:'auto',animation:'mi .3s cubic-bezier(.22,1,.36,1)'}} onClick={e=>e.stopPropagation()}><div style={{padding:'28px 24px 20px',borderBottom:'1px solid rgba(255,255,255,.05)',position:'relative'}}><button onClick={()=>setModal(null)} style={{position:'absolute',top:14,right:14,background:'rgba(255,255,255,.05)',border:'1px solid rgba(255,255,255,.08)',color:'rgba(255,255,255,.4)',width:34,height:34,borderRadius:9,cursor:'pointer',fontSize:15,display:'flex',alignItems:'center',justifyContent:'center'}}>✕</button><div style={{display:'flex',gap:6,flexWrap:'wrap',marginBottom:14}}><Tag cls="tm">{t.c}</Tag><span style={{fontFamily:'var(--m)',fontSize:11,color:'rgba(255,255,255,.3)'}}>{t.m} de lectura</span></div><div style={{fontSize:40,marginBottom:12}}>{t.i}</div><h2 style={{fontFamily:'var(--h)',fontSize:24,fontWeight:800,color:'#f5f5f0',margin:0,lineHeight:1.2,paddingRight:40}}>{t.t}</h2></div><div style={{padding:24,fontFamily:'var(--b)',fontSize:14,color:'rgba(255,255,255,.6)',lineHeight:1.7,whiteSpace:'pre-line'}}>{t.body}</div><div style={{padding:'0 24px 24px'}}><div style={{borderTop:'1px solid rgba(255,255,255,.05)',paddingTop:16,textAlign:'center'}}><p style={{fontFamily:'var(--b)',fontSize:13,color:'rgba(255,255,255,.3)',margin:'0 0 12px'}}>¿Te sirvió? Explorá el directorio para encontrar tu lugar.</p><a className="b1" href="#directorio" style={{fontSize:13,padding:'11px 22px'}} onClick={()=>setModal(null)}>Explorar directorio →</a></div></div></div></div>})()}

